insert into dsb_drama_script values ('2', 11, '0.2', 1010801023, '10', '1', '1', '0', 1010801, '0', 'あ、あづいです～っ！！\\nここのお湯の温度はおかしいですよ……\\nどうなってるですか、ボス！？');
