insert into dsb_drama_script values ('1', 11, '0.2', 1010801028, '10', '1', '1', '0', 1010801, '0', '今はボスじゃなくて\\n若女将って呼んでほしいな～？');
insert into dsb_drama_script values ('0', 91, '', 1010801029, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010801030, '1', '', '', '', 1010801, '0.5', 'dsb_idle_normal');
