insert into dsb_drama_script values ('1', 11, '0.2', 1010801038, '10', '1', '1', '0', 1010801, '0', 'イノリちゃん……\\n今なんか言った？');
insert into dsb_drama_script values ('0', 91, '', 1010801039, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010801040, '1', '', '', '', 1010801, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010801041, '0', 'dsb_talk_surprise1_2', '1', '0.5', 1010801, '0.2', 'dsb_surprise_inori');
insert into dsb_drama_script values ('vo_dsb_1010801', 21, '', 1010801042, '0', '0', '', '', 1010801, '', 'vo_dsb_1005');
insert into dsb_drama_script values ('2', 11, '0.2', 1010801043, '10', '1', '1', '0', 1010801, '0', 'いいい、いや何も言ってないですよ～？\\nそんなことより温泉です！\\nこの熱さはただごとじゃないです……\\n絶対ヤバいものが入ってるですよ！');
insert into dsb_drama_script values ('0', 91, '', 1010801044, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010801045, '1', '', '', '', 1010801, '0.5', 'dsb_idle_surprise1_normal');
insert into dsb_drama_script values ('1', 3, '', 1010801046, '1', '', '', '', 1010801, '0.5', 'dsb_talk_bitter');
insert into dsb_drama_script values ('vo_dsb_1010801', 21, '', 1010801047, '0', '0', '', '', 1010801, '', 'vo_dsb_1006');
insert into dsb_drama_script values ('1', 11, '0.2', 1010801048, '10', '1', '1', '0', 1010801, '0', '人聞きが悪いな～\\n危険なものなんて入ってないよ～\\n……むしろイノリちゃんだって\\nよく知ってるものだし？');
insert into dsb_drama_script values ('0', 91, '', 1010801049, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010801050, '1', '', '', '', 1010801, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010801051, '1', '', '', '', 1010801, '0.5', 'dsb_sniff');
insert into dsb_drama_script values ('vo_dsb_1010801', 21, '', 1010801052, '0', '0', '', '', 1010801, '', 'vo_dsb_1007');
insert into dsb_drama_script values ('2', 11, '0.2', 1010801053, '10', '1', '1', '0', 1010801, '0', '言われてみれば……クンクン。\\nこのお湯の匂い\\nどっかで嗅いだような気がするです。');
insert into dsb_drama_script values ('0', 91, '', 1010801054, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010801055, '1', '', '', '', 1010801, '0.5', 'dsb_idle_normal');
