insert into dsb_drama_script values ('vo_dsb_1010801', 21, '', 1010801057, '0', '0', '', '', 1010801, '', 'vo_dsb_1008');
insert into dsb_drama_script values ('1', 11, '0.2', 1010801058, '10', '1', '1', '0', 1010801, '0', 'そうでしょ～？\\n正解は～……\\nドラゴンもどきちゃんからもらった\\n食べると火が吹ける木の実でした～☆');
insert into dsb_drama_script values ('0', 91, '', 1010801059, '', '', '', '', 1010801, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010801060, '1', '', '', '', 1010801, '0.5', 'dsb_idle_normal');
