insert into dsb_drama_script values ('2', 11, '0.2', 1010802020, '10', '1', '1', '0', 1010802, '0', 'やっばー！\u3000おフロ、ひっろ～い☆\\n温泉きちゃった感まじパない！\\nそれにミサトっちにも会えるとか\\nちょーウケるし！\u3000アガる～♪');
