insert into dsb_drama_script values ('2', 11, '0.2', 1010802054, '10', '1', '1', '0', 1010802, '0', 'フンイキ変わるとバズるかもだし！\\nめっちゃかわいいおフロだったら\\nお客さんもジャンジャンだよ！');
insert into dsb_drama_script values ('0', 91, '', 1010802055, '', '', '', '', 1010802, '', '');
