insert into dsb_drama_script values ('2', 11, '0.2', 1010802064, '10', '1', '1', '0', 1010802, '0', 'んっとねー\\nやっぱお花はもっと浮かせるっしょ！\\nもちろんいろんなやつね！\\nカラフルだったらビビビッとくるし♪');
