insert into dsb_drama_script values ('1', 11, '0.2', 1010802069, '10', '1', '1', '0', 1010802, '0', 'まるで温泉のお花畑ね～♪\\n色とりどりのお花に囲まれて\\nお風呂に入れるなんて……うふふ♪\\n想像するだけで気持ちが華やぐわ～');
