insert into dsb_drama_script values ('1', 11, '0.2', 1010802083, '10', '1', '1', '0', 1010802, '0', 'お花にはね、その一つ一つに\\n意味があるの。\\n誰かに贈るときには\\n相手へのメッセージにもなるのよ～');
