insert into dsb_drama_script values ('1', 11, '0.2', 1010802087, '10', '1', '1', '0', 1010802, '0', 'ちなみに今日のお花の意味は……\\n『愛するあなたのために』\\nうふふ、素敵でしょう♪');
insert into dsb_drama_script values ('0', 91, '', 1010802088, '', '', '', '', 1010802, '', '');
