insert into dsb_drama_script values ('2', 11, '0.2', 1010802092, '10', '1', '1', '0', 1010802, '0', 'あ、愛する……！\\nちょ、それまじ……？\\nそんなの、ストレートで……\\nなんか…………ズルじゃん。');
