insert into dsb_drama_script values ('2', 3, '', 1010805037, '0', 'dsb_stand_up_loop', '1', '0.2', 1010805, '0.2', 'dsb_stand_up_in');
insert into dsb_drama_script values ('1', 3, '', 1010805038, '1', '', '', '', 1010805, '0.5', 'dsb_talk_surprise1_misato');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805039, '0', '0', '', '', 1010805, '', 'vo_dsb_5005');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805040, '10', '1', '1', '0', 1010805, '0', 'あらあら、もう上がっちゃうの？\\nせっかくの温泉なんだから\\nもうちょっとゆっくりしていって？');
insert into dsb_drama_script values ('0', 91, '', 1010805041, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010805042, '1', '', '', '', 1010805, '0.5', 'dsb_idle_surprise1_misato');
insert into dsb_drama_script values ('2', 3, '', 1010805043, '1', '', '', '', 1010805, '0.5', 'dsb_stand_talk_normal2');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805044, '0', '0', '', '', 1010805, '', 'vo_dsb_5006');
insert into dsb_drama_script values ('2', 11, '0.2', 1010805045, '10', '1', '1', '0', 1010805, '0', 'もう十分、疲れはとれたわ。\\nあんまり長湯しちゃうと\\nかえって時間がもったいないもの。\\n時は金なりよ！');
insert into dsb_drama_script values ('0', 91, '', 1010805046, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010805047, '1', '', '', '', 1010805, '0.5', 'dsb_stand_up_loop');
insert into dsb_drama_script values ('1', 3, '', 1010805048, '1', '', '', '', 1010805, '0.5', 'dsb_talk_sad2_blink2');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805049, '0', '0', '', '', 1010805, '', 'vo_dsb_5007');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805050, '10', '1', '1', '0', 1010805, '0', '時は金なり……\\nそうね\\nそういう考え方もあるわね～');
insert into dsb_drama_script values ('0', 91, '', 1010805051, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010805052, '1', '', '', '', 1010805, '0.5', 'dsb_talk_worry_misato');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805053, '0', '0', '', '', 1010805, '', 'vo_dsb_5008');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805054, '10', '1', '1', '0', 1010805, '0', 'でも……\\nたまには時間をぜいたくに使うのも\\nいいんじゃないかしら？');
insert into dsb_drama_script values ('0', 91, '', 1010805055, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010805056, '1', '', '', '', 1010805, '0.2', 'dsb_stand_wish_surprise_idle');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805057, '0', '0', '', '', 1010805, '', 'vo_dsb_5009');
insert into dsb_drama_script values ('2', 11, '0.2', 1010805058, '10', '1', '1', '0', 1010805, '0', 'え？');
insert into dsb_drama_script values ('0', 91, '', 1010805059, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010805060, '1', '', '', '', 1010805, '0.2', 'dsb_talk_wish_nervous');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805061, '0', '0', '', '', 1010805, '', 'vo_dsb_5010');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805062, '10', '1', '1', '0', 1010805, '0', '疲れがたまるのは体だけじゃないわ。\\nあんまり気を張りすぎたら\\n心だって疲れちゃうもの。');
insert into dsb_drama_script values ('0', 91, '', 1010805063, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010805064, '1', '', '', '', 1010805, '0.5', 'dsb_misato_talk_sad2_dere');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805065, '0', '0', '', '', 1010805, '', 'vo_dsb_5011');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805066, '10', '1', '1', '0', 1010805, '0', 'そういう目に見えないところを癒すのも\\n大切なことだって……\\n私は思うの♪');
insert into dsb_drama_script values ('0', 91, '', 1010805067, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010805068, '1', '', '', '', 1010805, '0.5', 'dsb_idle_normal_misato');
insert into dsb_drama_script values ('2', 3, '', 1010805069, '1', '', '', '', 1010805, '0.2', 'dsb_stand_thinking');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805070, '0', '0', '', '', 1010805, '', 'vo_dsb_5012');
insert into dsb_drama_script values ('2', 11, '0.2', 1010805071, '10', '1', '1', '0', 1010805, '0', 'た、たしかに……\\nそういう考え方もあるわね。\\nはるばるオーエドまで足を運んだんだし\\nこの機会を生かした方がいいのかも……');
insert into dsb_drama_script values ('0', 91, '', 1010805072, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010805073, '0', 'dsb_stand_talk_guts_loop', '1', '0.5', 1010805, '0.2', 'dsb_stand_talk_guts');
insert into dsb_drama_script values ('0', 22, '', 1010805074, '', '', '', '', 1010805, '', '0');
insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805075, '0', '0.9', '', '', 1010805, '', 'vo_dsb_5013');
insert into dsb_drama_script values ('2', 11, '0.2', 1010805076, '10', '1', '1', '0', 1010805, '0', '……分かったわ。\\nしっかりたっぷり時間を使って\\n徹底的にリラックスしてみせる！\\nこれも必要経費ってやつよ！');
insert into dsb_drama_script values ('0', 91, '', 1010805077, '', '', '', '', 1010805, '', '');
insert into dsb_drama_script values ('se_10044200', 23, '', 1010805078, '0', '', '', '', 1010805, '', 'se_10044200_get_out_water');
