insert into dsb_drama_script values ('vo_dsb_1010805', 21, '', 1010805081, '0', '0', '', '', 1010805, '', 'vo_dsb_5014');
insert into dsb_drama_script values ('1', 11, '0.2', 1010805082, '10', '1', '1', '0', 1010805, '0', 'うふふ、それがいいわ～\\n温泉はの～んびりするところだもの。\\nどうぞ、ごゆるりと♪');
