insert into dsb_drama_script values ('2', 3, '', 1010806018, '1', '', '', '', 1010806, '0.5', 'dsb_talk_memory_nervous');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806019, '0', '0', '', '', 1010806, '', 'vo_dsb_6001');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806020, '10', '1', '1', '0', 1010806, '0', 'あああああ～～っ！\\n燃えるっ！\\nわたくしの脂肪が燃えていますわ～っ！');
insert into dsb_drama_script values ('0', 91, '', 1010806021, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806022, '0', 'dsb_talk_guts_pain_loop', '1', '0.5', 1010806, '0.5', 'dsb_talk_guts_pain');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806023, '0', '0', '', '', 1010806, '', 'vo_dsb_6002');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806024, '10', '1', '1', '0', 1010806, '0', 'ブラック労働のストレスからの食欲！\\n食欲からのぜい肉！\\nこの私腹を肥やすのは却下ですわ！\\nすっきりごっそり清算しますわよ～！！');
insert into dsb_drama_script values ('0', 91, '', 1010806025, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806026, '1', '', '', '', 1010806, '0.5', 'dsb_idle_guts_pain');
insert into dsb_drama_script values ('1', 3, '', 1010806027, '1', '', '', '', 1010806, '0.5', 'dsb_talk_normal_joy');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806028, '0', '0', '', '', 1010806, '', 'vo_dsb_6003');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806029, '10', '1', '1', '0', 1010806, '0', '入浴時間には気をつけてね？\\n脂肪燃焼効果が高いから……\\n入りすぎると大変なことになるわよ。');
insert into dsb_drama_script values ('0', 91, '', 1010806030, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806031, '1', '', '', '', 1010806, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010806032, '1', '', '', '', 1010806, '0.5', 'dsb_talk_normal');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806033, '0', '0', '', '', 1010806, '', 'vo_dsb_6004');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806034, '10', '1', '1', '0', 1010806, '0', 'ええ、ええ！\u3000もちろんですわ！\\nそれにしても……短時間で\\nこれほどの温泉が用意できるとは。\\nさすがは『隻眼の悪魔』ですわね？');
insert into dsb_drama_script values ('0', 91, '', 1010806035, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806036, '1', '', '', '', 1010806, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('1', 3, '', 1010806037, '1', '', '', '', 1010806, '0.5', 'dsb_talk_sad2_surprise');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806038, '0', '0', '', '', 1010806, '', 'vo_dsb_6005');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806039, '10', '1', '1', '0', 1010806, '0', 'お褒めの言葉どうも。\\nといっても……\\n私はあなたの依頼に応えただけだけど。');
insert into dsb_drama_script values ('0', 91, '', 1010806040, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806041, '1', '', '', '', 1010806, '0.5', 'dsb_idle_sad_talk1');
insert into dsb_drama_script values ('2', 3, '', 1010806042, '1', '', '', '', 1010806, '0.5', 'dsb_talk_normal_dere2');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806043, '0', '0', '', '', 1010806, '', 'vo_dsb_6006');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806044, '10', '1', '1', '0', 1010806, '0', 'あらあらご謙遜ですこと。\\nもっとつけ入る隙を見せてくれたら\\nわたくしも楽ですのに。');
insert into dsb_drama_script values ('0', 91, '', 1010806045, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806046, '1', '', '', '', 1010806, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('1', 3, '', 1010806047, '1', '', '', '', 1010806, '0.5', 'dsb_talk_normal_suprise1');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806048, '0', '0', '', '', 1010806, '', 'vo_dsb_6007');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806049, '10', '1', '1', '0', 1010806, '0', '私が楽にしてあげるのは患者だけよ。\\n商売の取引相手は範囲外。');
insert into dsb_drama_script values ('0', 91, '', 1010806050, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806051, '1', '', '', '', 1010806, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010806052, '1', '', '', '', 1010806, '0.5', 'dsb_talk_thinking_dere');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806053, '0', '0', '', '', 1010806, '', 'vo_dsb_6008');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806054, '10', '1', '1', '0', 1010806, '0', 'あらあらあら手厳しいですわね\\nおそろしいですわね。\\n冷や汗をかいてしまいますわ～\\nそれはもうダクダクと……んん？');
insert into dsb_drama_script values ('0', 91, '', 1010806055, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806056, '1', '', '', '', 1010806, '0.3', 'dsb_talk_worry_anger');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806057, '0', '0', '', '', 1010806, '', 'vo_dsb_6009');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806058, '10', '1', '1', '0', 1010806, '0', 'この汗の量……\\nおかしくありませんこと？\\nいくら発汗作用が優れているからと\\nいっても、これは……');
insert into dsb_drama_script values ('0', 91, '', 1010806059, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806060, '1', '', '', '', 1010806, '0.5', 'dsb_talk_surprise3');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806061, '0', '0', '', '', 1010806, '', 'vo_dsb_6010');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806062, '10', '1', '1', '0', 1010806, '0', 'それに……\\n気のせいかしら？\\nなんだか肌がヒリついてきたような……');
insert into dsb_drama_script values ('0', 91, '', 1010806063, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806064, '1', '', '', '', 1010806, '0.5', 'dsb_idle_surprise1_sjhy2');
insert into dsb_drama_script values ('1', 3, '', 1010806065, '1', '', '', '', 1010806, '0.5', 'dsb_talk_nerrvous');
insert into dsb_drama_script values ('0', 22, '', 1010806066, '', '', '', '', 1010806, '', '0');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806067, '0', '0.9', '', '', 1010806, '', 'vo_dsb_6011');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806068, '10', '1', '1', '0', 1010806, '0', '……ねえ、クレジッタ。\\nあなた、秘書さんに出張だってウソを\\nついてここに来たのよね？');
insert into dsb_drama_script values ('0', 91, '', 1010806069, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806070, '1', '', '', '', 1010806, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010806071, '0', 'dsb_shock_credita_loop', '1', '0.5', 1010806, '0.5', 'dsb_shock_credita_in');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806072, '0', '0', '', '', 1010806, '', 'vo_dsb_6012');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806073, '10', '1', '1', '0', 1010806, '0', 'ギギギギクッ？\\nどうしてそれを！？');
insert into dsb_drama_script values ('0', 91, '', 1010806074, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806075, '1', '', '', '', 1010806, '0.5', 'dsb_idle_joy_sad');
insert into dsb_drama_script values ('1', 3, '', 1010806076, '1', '', '', '', 1010806, '0.5', 'dsb_talk_normal_joy');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806077, '0', '0', '', '', 1010806, '', 'vo_dsb_6013');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806078, '10', '1', '1', '0', 1010806, '0', '秘書さんからの依頼でね？\\n……虚偽の申請をしたお仕置きを\\nしてほしいって言われちゃったの。\\nだから……');
insert into dsb_drama_script values ('0', 91, '', 1010806079, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806080, '1', '', '', '', 1010806, '0.5', 'dsb_talk_sad2_talkjoy2');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806081, '0', '0', '', '', 1010806, '', 'vo_dsb_6014');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806082, '10', '1', '1', '0', 1010806, '0', 'この温泉……\\nちょっと刺激的にしておいたわ。\\nトウガラシをた～っぷり入れて、ね。');
insert into dsb_drama_script values ('0', 91, '', 1010806083, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806084, '1', '', '', '', 1010806, '0.5', 'dsb_idle_sad_talkjoy2');
insert into dsb_drama_script values ('2', 3, '', 1010806085, '0', 'dsb_talk_surprise_credita', '1', '0.5', 1010806, '0.5', 'dsb_surprise_credita');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806086, '0', '0', '', '', 1010806, '', 'vo_dsb_6015');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806087, '10', '1', '1', '0', 1010806, '0', 'んなっ……！？\\nなんてモノを入れてますの～っ！！');
insert into dsb_drama_script values ('0', 91, '', 1010806088, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010806089, '1', '', '', '', 1010806, '0.5', 'dsb_idle_joy_sad');
insert into dsb_drama_script values ('1', 3, '', 1010806090, '1', '', '', '', 1010806, '0.5', 'dsb_talk_surprise1_normal2');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806091, '0', '0', '', '', 1010806, '', 'vo_dsb_6016');
insert into dsb_drama_script values ('1', 11, '0.2', 1010806092, '10', '1', '1', '0', 1010806, '0', 'ああ、心配しないで。\\nちゃんと脂肪燃焼効果はあるから。\\nちなみに私もよく入ってるし。\\n健康に害はないわよ。');
insert into dsb_drama_script values ('0', 91, '', 1010806093, '', '', '', '', 1010806, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010806094, '1', '', '', '', 1010806, '0.5', 'dsb_idle_surprise1_sjhy');
insert into dsb_drama_script values ('2', 3, '', 1010806095, '1', '', '', '', 1010806, '0.3', 'dsb_hot_dead');
insert into dsb_drama_script values ('vo_dsb_1010806', 21, '', 1010806096, '0', '0', '', '', 1010806, '', 'vo_dsb_6017');
insert into dsb_drama_script values ('2', 11, '0.2', 1010806097, '10', '1', '1', '0', 1010806, '0', 'だからって……ああっ！！\\n目っ！\u3000刺激が目に！\u3000来ましたわ！\\nくうう……ですが報酬を払った以上\\n最大限利用しませんと～ッ！！！');
insert into dsb_drama_script values ('0', 91, '', 1010806098, '', '', '', '', 1010806, '', '');
