insert into dsb_drama_script values ('1', 11, '0.2', 1010807027, '10', '1', '1', '0', 1010807, '0', 'ありがと～☆\\nそう言ってもらえると\\n私も若女将として鼻が高いよ～♪');
insert into dsb_drama_script values ('0', 91, '', 1010807028, '', '', '', '', 1010807, '', '');
