insert into dsb_drama_script values ('2', 11, '0.2', 1010807032, '10', '1', '1', '0', 1010807, '0', 'よっ、オーエド一の若女将！\\n……って、【ドラゴンズネスト】ぉ！？\\nなんであんたがここに！？');
insert into dsb_drama_script values ('3.2', 93, '', 1010807033, '', '', '', '', 1010807, '', '1');
insert into dsb_drama_script values ('2', 3, '', 1010807034, '1', '', '', '', 1010807, '0.5', 'dsb_talk_surprise2');
