insert into dsb_drama_script values ('1', 3, '', 1010807037, '1', '', '', '', 1010807, '0.5', 'dsb_talk_joy3');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807038, '0', '0', '', '', 1010807, '', 'vo_dsb_7004');
insert into dsb_drama_script values ('1', 11, '0.2', 1010807039, '10', '1', '1', '0', 1010807, '0', 'わぁ～♪\\nキャルちゃんノリツッコミだ～\\nウワサ通りの切れ味鋭い名ツッコミ☆');
insert into dsb_drama_script values ('0', 91, '', 1010807040, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010807041, '1', '', '', '', 1010807, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010807042, '1', '', '', '', 1010807, '0.5', 'dsb_talk_sad_shy');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807043, '0', '0', '', '', 1010807, '', 'vo_dsb_7005');
insert into dsb_drama_script values ('2', 11, '0.2', 1010807044, '10', '1', '1', '0', 1010807, '0', '誰が言ってたのよ、そんなこと！？\\nまったく……\\nどうせならもっとマシなウワサが\\n流れてほしいもんだわ。');
insert into dsb_drama_script values ('0', 91, '', 1010807045, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010807046, '1', '', '', '', 1010807, '0.5', 'dsb_idle_sad');
insert into dsb_drama_script values ('1', 3, '', 1010807047, '1', '', '', '', 1010807, '0.5', 'dsb_talk_thinking_joy');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807048, '0', '0', '', '', 1010807, '', 'vo_dsb_7006');
insert into dsb_drama_script values ('1', 11, '0.2', 1010807049, '10', '1', '1', '0', 1010807, '0', '人の口に戸は立てられないもんね～\\n……そういうキャルちゃんだって\\nここのウワサを聞いてきたんでしょ？');
insert into dsb_drama_script values ('0', 91, '', 1010807050, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010807051, '1', '', '', '', 1010807, '0.5', 'dsb_idle_arm_crossed');
insert into dsb_drama_script values ('2', 3, '', 1010807052, '0', 'dsb_talk_arm_crossed_normal2_loop', '1', '0.5', 1010807, '0.3', 'dsb_talk_arm_crossed_normal2');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807053, '0', '0', '', '', 1010807, '', 'vo_dsb_7007');
insert into dsb_drama_script values ('2', 11, '0.2', 1010807054, '10', '1', '1', '0', 1010807, '0', 'まぁね。\\n魔力が回復する温泉があるって聞いて\\nあと……あたしは別に気にしてないけど\\nついでに肌もプルプルになるらしいし？');
insert into dsb_drama_script values ('5.9', 93, '', 1010807055, '', '', '', '', 1010807, '', '1');
insert into dsb_drama_script values ('2', 3, '', 1010807056, '1', '', '', '', 1010807, '0.5', 'dsb_talk_arm_crossed_surprise_loop');
insert into dsb_drama_script values ('1010807054', 91, '', 1010807057, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010807058, '1', '', '', '', 1010807, '0.5', 'dsb_talk_arm_crossed_joy_loop');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807059, '0', '0', '', '', 1010807, '', 'vo_dsb_7008');
insert into dsb_drama_script values ('2', 11, '0.2', 1010807060, '10', '1', '1', '0', 1010807, '0', 'たしかにじんわりと\\n魔力は回復してきてるし……\\nこのヌルヌルしたお湯の感じが\\n肌にも効きそうな気がするわ。');
insert into dsb_drama_script values ('0', 91, '', 1010807061, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010807062, '1', '', '', '', 1010807, '0.5', 'dsb_idle_arm_joy_crossed');
