insert into dsb_drama_script values ('1', 11, '0.2', 1010807065, '10', '1', '1', '0', 1010807, '0', 'そっか～♪\\nじゃあ今日の温泉は大成功だね☆\\n捕まえてきてもらったかいがあったよ～');
insert into dsb_drama_script values ('0', 91, '', 1010807066, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010807067, '1', '', '', '', 1010807, '0.5', 'dsb_idle_normal');
insert into dsb_drama_script values ('2', 3, '', 1010807068, '1', '', '', '', 1010807, '0.3', 'dsb_talk_normal');
