insert into dsb_drama_script values ('2', 11, '0.2', 1010807070, '10', '1', '1', '0', 1010807, '0', 'なかなかやるじゃない！\\n……ん？\u3000ちょっと待って。\\n捕まえてきてもらった……？');
insert into dsb_drama_script values ('2.9', 93, '', 1010807071, '', '', '', '', 1010807, '', '1');
insert into dsb_drama_script values ('2', 3, '', 1010807072, '1', '', '', '', 1010807, '0.3', 'dsb_talk_normal_jitome');
