insert into dsb_drama_script values ('1', 3, '', 1010807075, '1', '', '', '', 1010807, '0.5', 'dsb_talk_normal_joy');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807076, '0', '0', '', '', 1010807, '', 'vo_dsb_7011');
insert into dsb_drama_script values ('1', 11, '0.2', 1010807077, '10', '1', '1', '0', 1010807, '0', 'あれ？\u3000温泉の名前、見なかったの～？\\nこの今日の温泉は……\\n特製のポーションとゼラチナを混ぜた\\n当旅館自慢のゼラチナの湯で～す☆');
insert into dsb_drama_script values ('0', 91, '', 1010807078, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('1', 3, '', 1010807079, '1', '', '', '', 1010807, '0.5', 'dsb_idle_joy1');
insert into dsb_drama_script values ('2', 3, '', 1010807080, '1', '', '', '', 1010807, '0.5', 'dsb_talk_surprise2_anger2');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807081, '0', '0', '', '', 1010807, '', 'vo_dsb_7012');
insert into dsb_drama_script values ('2', 11, '0.2', 1010807082, '10', '1', '1', '0', 1010807, '0', 'ゼ……ゼラチナ風呂ぉ～～！？\\nそういえば、どこかでそんな\\n不穏な言葉を見たような気が……');
insert into dsb_drama_script values ('0', 91, '', 1010807083, '', '', '', '', 1010807, '', '');
insert into dsb_drama_script values ('2', 3, '', 1010807084, '1', '', '', '', 1010807, '0.5', 'dsb_talk_surprise1_shy');
