insert into dsb_drama_script values ('2', 11, '0.2', 1010807086, '10', '1', '1', '0', 1010807, '0', 'どうりでなんだか懐かしい感じの\\nする温泉だと思ったわ……じゃなくて！\\nなんてものを作ってんのよ！？');
insert into dsb_drama_script values ('5.6', 93, '', 1010807087, '', '', '', '', 1010807, '', '1');
insert into dsb_drama_script values ('2', 3, '', 1010807088, '1', '', '', '', 1010807, '0.5', 'dsb_talk_anger_Ex2');
