insert into dsb_drama_script values ('1', 3, '', 1010807090, '1', '', '', '', 1010807, '0.5', 'dsb_talk_surprise1_normal2');
insert into dsb_drama_script values ('vo_dsb_1010807', 21, '', 1010807091, '0', '0', '', '', 1010807, '', 'vo_dsb_7014');
insert into dsb_drama_script values ('1', 11, '0.2', 1010807092, '10', '1', '1', '0', 1010807, '0', 'でも効能はよかったでしょ～？\\nちなみに入浴時間に比例して\\n魔力の回復量も増大しちゃう\\n素敵仕様となっておりま～す☆');
